import React from 'react';
import Iframe from 'react-iframe';

function GameIFrame({ title, embed, maxWidth }) {
  // Dimensiones originales del juego
  const originalWidth = 600;
  const originalHeight = 600;

  // Calcula la relación de aspecto del juego
  const aspectRatio = originalWidth / originalHeight;

  // Calcula el ancho y el alto en función del ancho máximo
  const width = "100%";
  const height = "100%";

  window.coi = {
    shouldRegister: () => !reloadedBySelf,
    shouldDeregister: () => false,
    coepCredentialless: () => true,
    coepDegrade: () => true,
    doReload: () => window.location.reload(),
    quiet: false
  }

  return (
    <div className="card" style={{ width: '100%', maxWidth: '600px', margin: 'auto' }}>
      <div className="card-body" style={{ padding: 0 }}>
        <div style={{ position: 'relative', width: '100%', paddingBottom: '100%' }}>
          <Iframe
            frameborder="0"
            src={embed}
            title={title}
            width={width}
            height={height}
            allowfullscreen=""
            style={{ position: 'absolute', width: '100%', height: '100%' }}
          ></Iframe>
        </div>
      </div>
    </div>
  );
};

export default GameIFrame;
